import * as React from 'react';
import { graphql } from 'gatsby';
import { GatsbyImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import Layout from '../../components/layout';
import Link from '../../components/common/link';
import SectionMenu from '../../components/sections/menu';
import { Seo } from '../../components/seo';
import { works } from '../../libs/works';

export default function WorksTemplate(props) {
  const { data, params } = props;
  const slug = params.frontmatter__slug;

  const { markdownRemark } = data; // data.markdownRemark holds your post data
  const { html } = markdownRemark;

  const images = data.allFile.edges
    .filter(edge => edge.node.relativeDirectory === `works/${slug}`)
    .map(edge => edge.node.childImageSharp.gatsbyImageData);

  const currentIndex = works.findIndex(({ link }) => link === slug);
  const nextIndex = (currentIndex + 1) % works.length;
  const prevIndex = currentIndex === 0 ? works.length - 1 : currentIndex - 1;
  const nextLink = `/works/${works[nextIndex].link}`;
  const prevLink = `/works/${works[prevIndex].link}`;

  return (
    <Layout>
      <SectionMenu />
      <Box py={10}>
        <Grid container justifyContent='center' spacing={4}>
          {images.map((image, i) => {
            const isPortrait = image.width < image.height;
            const floatWidth = isPortrait ? '50%' : '75%';

            return (
              <Grid item xs={12} key={i}>
                <Box
                  sx={{
                    width: {
                      sm: floatWidth,
                      xs: '100%'
                    },
                    mx: 'auto',
                    pointerEvents: 'none',
                    userSelect: 'none'
                  }}
                  onClick={e => e.preventDefault()}
                  onMouseDown={e => e.preventDefault()}
                  onMouseUp={e => e.preventDefault()}
                  onContextMenu={e => {
                    e.preventDefault();
                  }}
                >
                  <GatsbyImage
                    image={image}
                    alt={`image-${i}`}
                    style={{
                      pointerEvents: 'none',
                      userSelect: 'none'
                    }}
                  />
                </Box>
              </Grid>
            );
          })}
          <Grid item xs={12}>
            <div dangerouslySetInnerHTML={{ __html: html }} />
          </Grid>
          <Grid item xs={12}>
            <Box
              sx={{
                display: 'flex',
                justifyContent: 'space-between'
              }}
            >
              <Box>
                <Link href={prevLink}>&lt; Prev</Link>
              </Box>
              <Box>
                <Link href={nextLink}>Next &gt;</Link>
              </Box>
            </Box>
          </Grid>
        </Grid>
      </Box>
    </Layout>
  );
}

export const pageQuery = graphql`
  query ($id: String!) {
    markdownRemark(id: { eq: $id }) {
      html
      frontmatter {
        slug
      }
    }
    allFile(
      sort: { relativePath: ASC }
      filter: { relativeDirectory: { glob: "works/*" } }
    ) {
      edges {
        node {
          relativeDirectory
          childImageSharp {
            gatsbyImageData(width: 1920)
          }
        }
      }
    }
  }
`;

export const Head = ({ params }) => {
  return <Seo title={`WORKS - ${params.frontmatter__slug}`} />;
};
